import test from "node:test";
import assert from "node:assert/strict";
import { ResponseCache } from "../src/cache.mjs";
import { makeVariantKey } from "../src/key.mjs";
import { parseVary } from "../src/vary.mjs";

test("Vary fields are normalized and deduplicated", () => {
  assert.deepEqual(
    parseVary("Accept-Encoding,  X-Device,accept-encoding"),
    ["accept-encoding", "x-device"],
  );
});

test("request header lookup is case insensitive", () => {
  const upper = makeVariantKey(
    "/asset",
    ["accept-language"],
    { "Accept-Language": "de" },
  );
  const lower = makeVariantKey(
    "/asset",
    ["accept-language"],
    { "accept-language": "de" },
  );
  assert.equal(upper, lower);
});

test("a wildcard response cannot be retrieved", () => {
  const cache = new ResponseCache();
  cache.put(
    "/private",
    { authorization: "Bearer one" },
    { headers: { vary: "*" }, body: "secret" },
  );
  assert.equal(
    cache.match("/private", { authorization: "Bearer two" }),
    undefined,
  );
});
